#include <stdio.h> 
 #include <string.h> 
 #include <stdbool.h> 
 #define TAMANHO_TABELA 10 
 typedef struct { 
 int chave; 
 char nome[50]; 
 bool esta_ocupada;  
 } Gaveta; 
 Gaveta tabela[TAMANHO_TABELA]; 
 int funcaoHash(int chave) { return chave % TAMANHO_TABELA; } 
 void inserir(int chave, const char* nome) { 
 int indice = funcaoHash(chave);
 tabela[indice].chave = chave; 
 strcpy(tabela[indice].nome, nome); 
 tabela[indice].esta_ocupada = true; 
 printf("Inserido: '%s' na gaveta %d (Usando a chave: %d)", nome, indice, chave); 
 } 
 void buscar(int chave) { 
 int indice = funcaoHash(chave); 
 if (tabela[indice].esta_ocupada && tabela[indice].chave == chave) { 
 printf("Encontrado: '%s' esta na gaveta %d", tabela[indice].nome, indice); 
 } else { 
 printf("Erro: Chave %d nao encontrada.", chave); 
 } 
 } 
 int main() { 
 for (int i = 0; i < TAMANHO_TABELA; i++) { 
 tabela[i].esta_ocupada = false; 
 } 
 printf("--- Guardando Dados ---"); 
 inserir(105, "Alice"); 
 inserir(202, "Bob"); 
 inserir(309, "Carol"); 
 printf("--- Buscando Dados ---"); 
 buscar(202); 
 buscar(105); 
 buscar(999); 
 return 0; 
 }

